+#[must_use]
+pub fn parse_http_status(error_message: &str) -> Option<u16> {
+    let marker = "HTTP ";
+    let start = error_message.find(marker)? + marker.len();
+    let mut digits = String::new();
+    for ch in error_message[start..].chars() {
+        if ch.is_ascii_digit() {
+            digits.push(ch);
+        } else {
+            break;
+        }
+    }
+    if digits.is_empty() {
+        return None;
+    }
+    digits.parse::<u16>().ok()
+}
