+            tool_id: "tool-2".to_string(),
+            content: vec![ContentBlock::Text(TextContent::new(
+                "Successfully replaced text in main.rs.",
+            ))],
+            details: Some(json!({
+                "diff": "-fn main() {}\n+fn main() {\n+    println!(\"hello\");\n+}"
+            })),
+        },
+    );
+    apply_pi(
+        &harness,
+        &mut app,
+        "PiMsg::ToolEnd(edit)",
