+    // Tool 3: bash with large output (auto-collapses).
+    apply_pi(
+        &harness,
+        &mut app,
+        "PiMsg::ToolStart(bash)",
+        PiMsg::ToolStart {
+            name: "bash".to_string(),
+            tool_id: "tool-3".to_string(),
+        },
+    );
+    apply_pi(
+        &harness,
+        &mut app,
+        "PiMsg::ToolUpdate(bash) large",
