+    let step = apply_pi(
+        &harness,
+        &mut app,
+        "PiMsg::ToolEnd(bash)",
+        PiMsg::ToolEnd {
+            name: "bash".to_string(),
+            tool_id: "tool-3".to_string(),
+            is_error: false,
+        },
+    );
+
+    assert_after_contains(&harness, &step, "fn main() {}");
+    assert_after_contains(&harness, &step, "@@ main.rs @@");
